content.content:
[
  {
    "image": "cockroachdb/cockroach:v23.2.10",
    "imagePullPolicy": "IfNotPresent",
    "name": "cockroachdb",
    "resources": {},
    "terminationMessagePath": "/dev/termination-log",
    "terminationMessagePolicy": "File"
  },
  {
    "command": [
      "/bin/bash",
      "-c",
      "exec /cockroach/cockroach start --logtostderr=INFO --insecure --advertise-host=$(POD_NAME).crdb-cluster.cockroachdb.svc.cluster.local --http-addr=0.0.0.0:8080 --port=26257 --cache=25% --max-sql-memory=25% --join=crdb-cluster-0.crdb-cluster.cockroachdb.svc.cluster.local:26257,crdb-cluster-1.crdb-cluster.cockroachdb.svc.cluster.local:26257,crdb-cluster-2.crdb-cluster.cockroachdb.svc.cluster.local:26257"
    ],
    "env": [
      {
        "name": "POD_NAME",
        "valueFrom": {
          "fieldRef": {
            "apiVersion": "v1",
            "fieldPath": "metadata.name"
          }
        }
      },
      {
        "name": "POD_NAMESPACE",
        "valueFrom": {
          "fieldRef": {
            "apiVersion": "v1",
            "fieldPath": "metadata.namespace"
          }
        }
      }
    ],
    "image": "cockroachdb/cockroach:v23.2.7",
    "imagePullPolicy": "IfNotPresent",
    "livenessProbe": {
      "failureThreshold": 3,
      "httpGet": {
        "path": "/health",
        "port": "http",
        "scheme": "HTTP"
      },
      "initialDelaySeconds": 30,
      "periodSeconds": 5,
      "successThreshold": 1,
      "timeoutSeconds": 1
    },
    "name": "db",
    "ports": [
      {
        "containerPort": 26257,
        "name": "grpc",
        "protocol": "TCP"
      },
      {
        "containerPort": 8080,
        "name": "http",
        "protocol": "TCP"
      }
    ],
    "readinessProbe": {
      "failureThreshold": 2,
      "httpGet": {
        "path": "/health?ready=1",
        "port": "http",
        "scheme": "HTTP"
      },
      "initialDelaySeconds": 10,
      "periodSeconds": 5,
      "successThreshold": 1,
      "timeoutSeconds": 1
    },
    "resources": {
      "limits": {
        "cpu": "1",
        "memory": "2Gi"
      },
      "requests": {
        "cpu": "1",
        "memory": "2Gi"
      }
    },
    "terminationMessagePath": "/dev/termination-log",
    "terminationMessagePolicy": "File",
    "volumeMounts": [
      {
        "mountPath": "/cockroach/cockroach-data",
        "name": "datadir"
      }
    ]
  }
]

input.command:
kubectl -n cockroachdb patch sts crdb-cluster --type=json -p '[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers",
    "value": [
      {
        "command": ["/bin/bash", "-c", "exec /cockroach/cockroach start --logtostderr=INFO --insecure --advertise-host=$(POD_NAME).crdb-cluster.cockroachdb.svc.cluster.local --http-addr=0.0.0.0:8080 --port=26257 --cache=25% --max-sql-memory=25% --join=crdb-cluster-0.crdb-cluster.cockroachdb.svc.cluster.local:26257,crdb-cluster-1.crdb-cluster.cockroachdb.svc.cluster.local:26257,crdb-cluster-2.crdb-cluster.cockroachdb.svc.cluster.local:26257"],
        "env": [
          {"name": "POD_NAME", "valueFrom": {"fieldRef": {"apiVersion": "v1", "fieldPath": "metadata.name"}}},
          {"name": "POD_NAMESPACE", "valueFrom": {"fieldRef": {"apiVersion": "v1", "fieldPath": "metadata.namespace"}}}
        ],
        "image": "cockroachdb/cockroach:v23.2.10",
        "imagePullPolicy": "IfNotPresent",
        "livenessProbe": {
          "failureThreshold": 3,
          "httpGet": {"path": "/health", "port": "http", "scheme": "HTTP"},
          "initialDelaySeconds": 30, "periodSeconds": 5, "successThreshold": 1, "timeoutSeconds": 1
        },
        "name": "db",
        "ports": [
          {"containerPort": 26257, "name": "grpc", "protocol": "TCP"},
          {"containerPort": 8080, "name": "http", "protocol": "TCP"}
        ],
        "readinessProbe": {
          "failureThreshold": 2,
          "httpGet": {"path": "/health?ready=1", "port": "http", "scheme": "HTTP"},
          "initialDelaySeconds": 10, "periodSeconds": 5, "successThreshold": 1, "timeoutSeconds": 1
        },
        "resources": {
          "limits": {"cpu": "1", "memory": "2Gi"},
          "requests": {"cpu": "1", "memory": "2Gi"}
        },
        "terminationMessagePath": "/dev/termination-log",
        "terminationMessagePolicy": "File",
        "volumeMounts": [{"mountPath": "/cockroach/cockroach-data", "name": "datadir"}]
      }
    ]
  },
  {"op": "replace", "path": "/spec/updateStrategy/rollingUpdate/partition", "value": 2}
]'
